## 🔹 Sample 4: Mark-and-Sweep GC (mark_and_sweep.fl - 407줄)

구현 대상: 순환 참조 해결을 위한 Tricolor marking

enum TricolorStatus {
    White,      // Unreachable (candidate for collection)
    Gray,       // Marked reachable, children pending
    Black,      // Fully processed (alive)
}

fn mark_phase(heap: &GCHeap, roots: [u64]) -> &GCHeap {
    // Initialize: all objects are white
    for obj in heap.objects {
        obj.color = TricolorStatus.White
    }

    // Root objects become gray
    let mut gray_set = []
    for root_id in roots {
        for obj in heap.objects {
            if obj.id == root_id {
                obj.color = TricolorStatus.Gray
                gray_set.push(obj)
            }
        }
    }

    // Process gray objects
    while len(gray_set) > 0 {
        let obj = gray_set.pop()

        // Mark children
        for child_id in obj.references {
            for child_obj in heap.objects {
                if child_obj.id == child_id && child_obj.color == TricolorStatus.White {
                    child_obj.color = TricolorStatus.Gray
                    gray_set.push(child_obj)
                }
            }
        }

        // Mark self as black
        obj.color = TricolorStatus.Black
    }

    heap
}

fn sweep_phase(heap: &GCHeap) -> &GCHeap {
    let mut survived = []

    for obj in heap.objects {
        if obj.color == TricolorStatus.Black {
            // Alive - keep it
            survived.push(obj)
        } else {
            // Dead - collect (deallocate)
            heap.total_collected = heap.total_collected + obj.size
        }
    }

    heap.objects = survived
    heap
}

fn mark_and_sweep(heap: &GCHeap, roots: [u64]) -> &GCHeap {
    let heap = mark_phase(heap, roots)
    sweep_phase(heap)
}

