fn test_hash_chain_audit_log() {
    println!("🔗 Hash-Chained Audit Log Tests");

    let mut log = new_audit_log();

    // Record first context switch
    log = record_context_switch(
        log,
        "INIT".to_string(),
        0x7FFFFFFF0000,
        0,
        1
    );

    // Record more switches
    log = record_context_switch(
        log,
        "SWITCH_1".to_string(),
        0x7FFFFFFF0000,
        0,
        2
    );

    log = record_context_switch(
        log,
        "SWITCH_2".to_string(),
        0x7FFFFFFF0000,
        0,
        3
    );

    // Verify the chain
    let chain_valid = verify_chain(log);

    if chain_valid {
        println!("  ✅ Chain integrity verified");
    } else {
        println!("  ❌ Chain integrity failed");
    }

    println!("  Total entries: {}", log.entry_count);
    println!("  Total hashes: {}", log.total_hashes);
    println!("  Verified: {}", log.verified_hashes);
}

