fn original_array_sum(arr: [u64]) -> u64 {
    let mut sum = 0u64;
    let mut i = 0usize;

    while i < arr.len() {
        sum = sum + arr[i];
        i = i + 1usize;
    }

    sum
}

// Optimized implementation: Fold operation (conceptually)
fn optimized_array_sum(arr: [u64]) -> u64 {
