            println!("    ❌ Array sum MISMATCH");
            mismatches = mismatches + 1u64;
        }
        execution_count = execution_count + 1u64;
    }

    // Test 3: Context switch equivalence
    println!("\n  Test 3: Context Switches");
    let test_switches: [u64] = [1, 10, 100, 1000, 1000000];

    for target in test_switches {
        if test_context_switch_equivalence(target) {
            println!("    ✅ Switches({}) matches", target);
        } else {
            println!("    ❌ Switches({}) MISMATCH", target);
            mismatches = mismatches + 1u64;
        }
        execution_count = execution_count + 1u64;
    }

    ExecutionResult {
        original_result: 0,
        optimized_result: 0,
        matches: mismatches == 0u64,
        execution_count: execution_count,
        mismatches: mismatches,
    }
}

fn test_differential_execution() {
    println!("\n🔀 DIFFERENTIAL EXECUTION SUITE");
    println!("═════════════════════════════════════");

    let result = run_differential_execution_tests();

    println!("\n📊 Results:");
    println!("  Total Tests: {}", result.execution_count);
    println!("  Mismatches: {}", result.mismatches);

    if result.matches {
        println!("  ✅ ALL TESTS MATCH - Optimization is correct");
    } else {
        println!("  ❌ MISMATCHES DETECTED - Optimization broke semantics");
    }
}

